// Middleware pipeline using delegates
public delegate Task Middleware(HttpContext ctx, Func<Task> next);

public class Pipeline
{
    private readonly List<Middleware> middlewares = new();

    public Pipeline Use(Middleware m) { middlewares.Add(m); return this; }

    public async Task Execute(HttpContext ctx)
    {
        int index = 0;
        async Task Next()
        {
            if (index < middlewares.Count)
                await middlewares[index++](ctx, Next);
        }
        await Next();
    }
}

