ref struct TokenParser
{
    private ReadOnlySpan<char> remaining;

    public TokenParser(ReadOnlySpan<char> input) => remaining = input;

    public ReadOnlySpan<char> NextToken()
    {
        remaining = remaining.TrimStart();
        var space = remaining.IndexOf(' ');
        if (space < 0) { var tok = remaining; remaining = default; return tok; }
        var token = remaining[..space];
        remaining = remaining[(space+1)..];
        return token;
    }
}

